package kotlinx.coroutines

import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.time.Duration
import kotlin.time.Duration.Companion.milliseconds
import kotlin.time.Duration.Companion.nanoseconds

class ToDelayMillisRoundingTest : TestBase() {

    @Test
    fun testRoundsUpSubMillisecondRemainder() {
        val d = 998.milliseconds + 902_752.nanoseconds
        assertEquals(999L, d.toDelayMillis())
    }

    @Test
    fun testDoesNotRoundExactMilliseconds() {
        assertEquals(998L, 998.milliseconds.toDelayMillis())
    }

    @Test
    fun testCoercesPositiveToAtLeastOneMillisecond() {
        assertEquals(1L, 1.nanoseconds.toDelayMillis())
        assertEquals(1L, 999_999.nanoseconds.toDelayMillis())
    }

    @Test
    fun testCoercesNonPositiveToZero() {
        assertEquals(0L, Duration.ZERO.toDelayMillis())
        assertEquals(0L, (-1).milliseconds.toDelayMillis())
    }

    @Test
    fun testInfiniteCoercesToLongMaxValue() {
        assertEquals(Long.MAX_VALUE, Duration.INFINITE.toDelayMillis())
    }
}
"}

